809	assign  wr_dx_num[4:0]     = remain_wr_dx      >= 4'h7  ? 4'h7 : remain_wr_dx ; 
810	assign  wr_width_num[4:0]  = remain_wr_width   >= 4'h7  ? 4'h7 : remain_wr_width[4:0];
811	assign  wr_planar_num[4:0] = remain_wr_channel >= {8'h0,kpg_dec} ? kpg_dec : remain_wr_channel[4:0];
812	
813	//merge and split of read total column unit is element(1byte or 2byte), but contract unit is 32bytes
814	assign  rd_total_col[5:0] = m_contract ? (|x_stride[4:3] ? {1'b0,wr_dx_num} : {1'b0,x_stride}) : m_merge ? {1'b0,wr_planar_num[4:0]} : merge_wr_size[5:0]; 
815	assign  rd_total_row[5:0] = m_contract ? (|x_stride[4:3] ? {1'b0,wr_width_num[4:0]} : 1'b0) : m_merge ? merge_wr_size[5:0] : {1'b0,wr_planar_num[4:0]}; 
816	assign  contract_lit_dx   = m_contract & ~(|x_stride[4:3]); 
817	
818	assign  rf_rd_cmd_vld = wr_plar_beg | wr_hx_beg | (m_contract & ~(|x_stride[4:3]) | m_merge) & wr_req_accept;
819	assign  rf_rd_cmd_pd  = {rd_total_row,rd_total_col};
820	/*
821	&Always posedge;
822	    if (wr_plar_beg | wr_hx_beg | (m_contract & ~(|x_stride[4:3]) | m_merge) & wr_req_accept) begin
823	        rf_rd_cmd_vld <0=1'b1;
824	        rf_rd_cmd_pd  <0= {rd_total_row,rd_total_col};
825	    end
826	    else if (rf_rd_cmd_vld & rf_rd_cmd_rdy)
827	        rf_rd_cmd_vld <0=1'b0;
828	&End;
829	*/
830	
831	///////generate write sequence address/////////
832	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
833	  if (!nvdla_core_rstn) begin
834	    wr_addr <= {59{1'b0}};
835	    {mon_wr_addr_c,wr_addr} <= {60{1'b0}};
836	  end else begin
837	    if(init_set)
838	       wr_addr <= dest_base;
839	    else if(wr_height_end)            
840	       {mon_wr_addr_c,wr_addr} <= wr_chn_base + out_chn_stride     ; 
841	    else if(wr_width_end) 
842	       {mon_wr_addr_c,wr_addr} <= wr_line_base + out_line_stride   ;
843	    else if(wr_dx_end | wr_plar_end)  
844	       {mon_wr_addr_c,wr_addr} <= wr_width_base + out_width_stride ;
845	    else if(wr_hx_end)  
846	       {mon_wr_addr_c,wr_addr} <= wr_dx_base + 4'h8;
847	    else if(wr_req_accept)            
848	       {mon_wr_addr_c,wr_addr} <= wr_addr + out_intern_stride      ; 
849	  end
850	end
851	
852	//record the pointer base address
853	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
854	  if (!nvdla_core_rstn) begin
855	    wr_dx_base <= {59{1'b0}};
856	    {mon_wr_xbase_c,wr_dx_base} <= {60{1'b0}};
857	  end else begin
858	    if(init_set)
859	       wr_dx_base <= dest_base;
860	    else if(wr_height_end)            
861	       {mon_wr_xbase_c,wr_dx_base} <= wr_chn_base + out_chn_stride     ; 
862	    else if(wr_width_end) 
863	       {mon_wr_xbase_c,wr_dx_base} <= wr_line_base + out_line_stride   ;
864	    else if(wr_dx_end | wr_plar_end)  
865	       {mon_wr_xbase_c,wr_dx_base} <= wr_width_base + out_width_stride ;
866	    else if(wr_hx_end)
867	       {mon_wr_xbase_c,wr_dx_base} <= wr_dx_base + 4'h8;
868	  end
869	end
870	
871	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
872	  if (!nvdla_core_rstn) begin
873	    wr_width_base <= {59{1'b0}};
874	    {mon_wr_wbase_c,wr_width_base} <= {60{1'b0}};
875	  end else begin
876	    if(init_set)
877	       wr_width_base <= dest_base;
878	    else if(wr_height_end)            
879	       {mon_wr_wbase_c,wr_width_base} <= wr_chn_base + out_chn_stride     ; 
880	    else if(wr_width_end) 
881	       {mon_wr_wbase_c,wr_width_base} <= wr_line_base + out_line_stride   ;
882	    else if(wr_dx_end | wr_plar_end)
883	       {mon_wr_wbase_c,wr_width_base} <= wr_width_base + out_width_stride;
884	  end
885	end
886	
887	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
888	  if (!nvdla_core_rstn) begin
889	    wr_line_base <= {59{1'b0}};
890	    {mon_wr_lbase_c,wr_line_base} <= {60{1'b0}};
891	  end else begin
892	    if(init_set)
893	       wr_line_base <= dest_base;
894	    else if(wr_height_end)            
895	       {mon_wr_lbase_c,wr_line_base} <= wr_chn_base + out_chn_stride     ; 
896	    else if(wr_width_end)
897	       {mon_wr_lbase_c,wr_line_base} <= wr_line_base + out_line_stride;
898	  end
899	end
900	
901	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
902	  if (!nvdla_core_rstn) begin
903	    wr_chn_base <= {59{1'b0}};
904	    {mon_wr_cbase_c,wr_chn_base} <= {60{1'b0}};
905	  end else begin
906	    if(init_set)
907	       wr_chn_base <= dest_base;
908	    else if(wr_height_end)
909	       {mon_wr_cbase_c,wr_chn_base} <= wr_chn_base + out_chn_stride;
910	  end
911	end
912	
913	///////////for circle counter/////////////
914	//internal counter
915	assign  wr_hx_beg   = m_contract & (|x_stride[4:3]) & wr_req_accept & (wr_plar_cnt == 0);
916	assign  wr_hx_end   = m_contract & (|x_stride[4:3]) & wr_req_accept & (wr_plar_cnt == wr_width_num);
917	assign  wr_plar_beg = m_split & wr_req_accept & (wr_plar_cnt == 0);
918	assign  wr_plar_end = m_split & wr_req_accept & (wr_plar_cnt == wr_planar_num);
919	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
920	  if (!nvdla_core_rstn) begin
921	    wr_plar_cnt <= {5{1'b0}};
922	  end else begin
923	    if (!rubik_en | wr_hx_end | wr_plar_end) begin
924	        wr_plar_cnt <= 0;
925	    end 
926	    else if ((m_contract & (|x_stride[4:3]) | m_split) & wr_req_accept) begin
927	        wr_plar_cnt <= wr_plar_cnt + 1;
928	    end
929	  end
930	end
931	
932	//deconv x counter
933	assign  wr_dx_cnt_inc[2:0] = wr_dx_cnt + 1'b1;
934	assign  {mon_dx_stride_num_c,dx_stride_num[2:0]} = x_stride_add[5:3]+|x_stride_add[2:0];
935	assign  wr_dx_end = wr_hx_end & (wr_dx_cnt_inc >= dx_stride_num);
936	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
937	  if (!nvdla_core_rstn) begin
938	    wr_dx_cnt <= {2{1'b0}};
939	    {mon_wr_dx_cnt,wr_dx_cnt} <= {3{1'b0}};
940	  end else begin
941	    if (!rubik_en | wr_dx_end) begin
942	        wr_dx_cnt <= 0;
943	    end 
944	    else if (wr_hx_end) begin
945	        {mon_wr_dx_cnt,wr_dx_cnt} <= wr_dx_cnt_inc;
946	    end
947	  end
948	end
949	
950	//write width counter
951	assign  wr_cwdth_cnt_inc[10:0] = wr_width_cnt + 1'b1; 
952	assign  wr_mwdth_cnt_inc[10:0] = wr_width_cnt + 4'h8; 
953	assign  wr_cwdth_end = wr_dx_end & (wr_cwdth_cnt_inc >= inwidthm[10:0]); 
954	assign  wr_mwdth_end =(wr_plar_end | m_merge & wr_req_accept) & (wr_mwdth_cnt_inc >= inwidthm[10:0]);
955	assign  wr_width_end = wr_cwdth_end | wr_mwdth_end;
956	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
957	  if (!nvdla_core_rstn) begin
958	    wr_width_cnt <= {10{1'b0}};
959	    {mon_wr_width_cnt,wr_width_cnt} <= {11{1'b0}};
960	  end else begin
961	    if (!rubik_en | wr_width_end) begin
962	        wr_width_cnt <= 0;
963	    end 
964	    else if(wr_dx_end) begin
965	        {mon_wr_width_cnt,wr_width_cnt} <= wr_cwdth_cnt_inc;
966	    end
967	    else if(wr_plar_end | m_merge & wr_req_accept) begin
968	        {mon_wr_width_cnt,wr_width_cnt} <= wr_mwdth_cnt_inc;
969	    end
970	  end
971	end
972	
973	//write height counter
974	assign  wr_cheight_end = (wr_cwdth_end | m_contract & ~(|x_stride[4:3]) & wr_req_accept) & (wr_line_cnt == inheight_mul_dy);
975	assign  wr_mheight_end = wr_mwdth_end & (wr_line_cnt == {5'h0,inheight_raw});
976	assign  wr_height_end  = wr_cheight_end | wr_mheight_end;
977	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
978	  if (!nvdla_core_rstn) begin
979	    wr_line_cnt <= {18{1'b0}};
980	  end else begin
981	    if (!rubik_en | wr_height_end) begin
982	        wr_line_cnt <= 0;
983	    end 
984	    else if(wr_width_end | m_contract & ~(|x_stride[4:3]) & wr_req_accept) begin
985	        wr_line_cnt <= wr_line_cnt + 1;
986	    end
987	  end
988	end
989	
990	//write channel counter
991	assign  wr_chn_cnt_inc[9:0] = wr_chn_cnt + kpgm;
992	assign  {mon_outchannelm_c,outchannelm[9:0]} = outchannel[13:4]+|outchannel[3:0];
993	assign  wr_channel_end = wr_height_end & (wr_chn_cnt_inc >= outchannelm[9:0]);
994	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
995	  if (!nvdla_core_rstn) begin
996	    wr_chn_cnt <= {9{1'b0}};
997	    {mon_wr_chn_cnt,wr_chn_cnt} <= {10{1'b0}};
998	  end else begin
999	    if (!rubik_en | wr_channel_end) begin
1000	        wr_chn_cnt <= 0;
1001	    end 
1002	    else if(wr_height_end) begin
1003	        {mon_wr_chn_cnt,wr_chn_cnt} <= wr_chn_cnt_inc;
1004	    end
1005	  end
1006	end
1007	
1008	
1009	//VCS coverage off
1010	`ifndef DISABLE_FUNCPOINT
1011	  `ifdef ENABLE_FUNCPOINT
1012	
1013	    reg funcpoint_cover_off;
1014	    initial begin
1015	        if ( $test$plusargs( "cover_off" ) ) begin
1016	            funcpoint_cover_off = 1'b1;
1017	        end else begin
1018	            funcpoint_cover_off = 1'b0;
1019	        end
1020	    end
1021	
1022	    property rubik_seq_gen__read_request_block__0_cov;
1023	        disable iff((nvdla_core_rstn !== 1) || funcpoint_cover_off)
1024	        @(posedge nvdla_core_clk)
1025	        rd_req_vld & !rd_req_rdy;
1026	    endproperty
1027	    // Cover 0 : "rd_req_vld & !rd_req_rdy"
1028	    FUNCPOINT_rubik_seq_gen__read_request_block__0_COV : cover property (rubik_seq_gen__read_request_block__0_cov);
1029	
1030	  `endif
1031	`endif
1032	//VCS coverage on
1033	
1034	
1035	
1036	
1037	
1038	    assign rd_stall_cnt_dec = 1'b0;
1039	
1040	    // stl adv logic
1041	
1042	    always @(
1043	      rd_req_vld
1044	      or rd_stall_cnt_dec
1045	      ) begin
1046	      stl_adv = rd_req_vld ^ rd_stall_cnt_dec;
1047	    end
1048	        
1049	    // stl cnt logic
1050	    always @(
1051	      stl_cnt_cur
1052	      or rd_req_vld
1053	      or rd_stall_cnt_dec
1054	      or stl_adv
1055	      or rd_req_done
1056	      ) begin
1057	      // VCS sop_coverage_off start
1058	      stl_cnt_ext[33:0] = {1'b0, 1'b0, stl_cnt_cur};
1059	      stl_cnt_inc[33:0] = stl_cnt_cur + 1'b1; // spyglass disable W164b
1060	      stl_cnt_dec[33:0] = stl_cnt_cur - 1'b1; // spyglass disable W164b
1061	      stl_cnt_mod[33:0] = (rd_req_vld && !rd_stall_cnt_dec)? stl_cnt_inc : (!rd_req_vld && rd_stall_cnt_dec)? stl_cnt_dec : stl_cnt_ext;
1062	      stl_cnt_new[33:0] = (stl_adv)? stl_cnt_mod[33:0] : stl_cnt_ext[33:0];
1063	      stl_cnt_nxt[33:0] = (rd_req_done)? 34'd0 : stl_cnt_new[33:0];
1064	      // VCS sop_coverage_off end
1065	    end
1066	
1067	    // stl flops
1068	
1069	    always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
1070	      if (!nvdla_core_rstn) begin
1071	        stl_cnt_cur[31:0] <= 0;
1072	      end else begin
1073	      if (reg2dp_perf_en) begin
1074	      stl_cnt_cur[31:0] <= stl_cnt_nxt[31:0];
1075	      end
1076	      end
1077	    end
1078	
1079	    // stl output logic
1080	
1081	    always @(
1082	      stl_cnt_cur
1083	      ) begin
1084	      rd_stall_cnt[31:0] = stl_cnt_cur[31:0];
1085	    end
1086	        
1087	      
1088	
1089	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
1090	  if (!nvdla_core_rstn) begin
1091	    dp2reg_d0_rd_stall_cnt <= {32{1'b0}};
1092	  end else begin
1093	   if (rd_req_done & ~dp2reg_consumer)
1094	       dp2reg_d0_rd_stall_cnt <= rd_stall_cnt; 
1095	  end
1096	end
1097	
1098	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
1099	  if (!nvdla_core_rstn) begin
1100	    dp2reg_d1_rd_stall_cnt <= {32{1'b0}};
1101	  end else begin
1102	   if (rd_req_done & dp2reg_consumer)
1103	       dp2reg_d1_rd_stall_cnt <= rd_stall_cnt; 
1104	  end
1105	end
1106	
1107	endmodule // NV_NVDLA_RUBIK_seq_gen
1108	
1109

