138	wire          rf_wr_cmd_ordy;
139	wire          rf_wr_cmd_ovld;
140	wire          rf_wr_col_end;
141	wire    [5:0] rf_wr_rcnt_inc;
142	wire          rf_wr_row_end;
143	wire   [11:0] split_rd_mask;
144	wire    [6:0] wr_total_col;
145	wire    [5:0] wr_total_colm;
146	wire    [6:0] wr_total_pcol;
147	wire    [5:0] wr_total_prow;
148	wire    [5:0] wr_total_row;
149	
150	// synoff nets
151	
152	// monitor nets
153	
154	// debug nets
155	
156	// tie high nets
157	
158	// tie low nets
159	
160	// no connect nets
161	
162	// not all bits used nets
163	
164	// todo nets
165	
166	    
167	
168	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
169	  if (!nvdla_core_rstn) begin
170	    reg2dp_rubik_mode_drv1[1:0] <= {2{1'b0}};
171	  end else begin
172	  reg2dp_rubik_mode_drv1[1:0] <= reg2dp_rubik_mode[1:0];
173	  end
174	end
175	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
176	  if (!nvdla_core_rstn) begin
177	    reg2dp_in_precision_drv1[1:0] <= {2{1'b0}};
178	  end else begin
179	  reg2dp_in_precision_drv1[1:0] <= reg2dp_in_precision[1:0];
180	  end
181	end
182	
183	assign  m_contract  = reg2dp_rubik_mode_drv1[1:0] == 2'h0 ;
184	assign  m_split     = reg2dp_rubik_mode_drv1[1:0] == 2'h1 ;
185	//assign  m_merge     = reg2dp_rubik_mode_drv1[1:0] == NVDLA_RBK_D_MISC_CFG_0_RUBIK_MODE_MERGE;
186	assign  m_byte_data = reg2dp_in_precision_drv1[1:0] == 2'h0 ;
187	
188	////////////////////////////////////////////////////////////////////////////////
189	//////////////pop total row,total columun from rf_wr_cmd_fifo//////////
190	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
191	  if (!nvdla_core_rstn) begin
192	    rf_wr_cmd_ordy_hold <= 1'b1;
193	  end else begin
194	    if (rf_wr_cmd_ordy_hold & rf_wr_cmd_ovld)  
195	        rf_wr_cmd_ordy_hold <= 1'b0;
196	    else if(rf_wr_row_end & ~rf_wr_cmd_ovld) 
197	        rf_wr_cmd_ordy_hold <= 1'b1;
198	  end
199	end
200	
201	assign  rf_wr_cmd_ordy = rf_wr_row_end | rf_wr_cmd_ordy_hold;
202	
203	assign  wr_total_pcol[6:0] = rf_wr_cmd_opd[5:0]+1; 
204	assign  wr_total_prow[5:0] = rf_wr_cmd_opd[10:6]+1; 
205	
206	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
207	  if (!nvdla_core_rstn) begin
208	    wr_total_col_reg[6:0] <= {7{1'b0}};
209	    wr_total_row_reg[5:0] <= {6{1'b0}};
210	  end else begin
211	    if (rf_wr_cmd_ovld & rf_wr_cmd_ordy) begin  
212	        wr_total_col_reg[6:0] <= wr_total_pcol[6:0];
213	        wr_total_row_reg[5:0] <= wr_total_prow[5:0];
214	    end
215	  end
216	end
217	
218	assign  wr_total_col[6:0] = wr_total_col_reg[6:0]; 
219	assign  wr_total_row[5:0] = wr_total_row_reg[5:0]; 
220	
221	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
222	  if (!nvdla_core_rstn) begin
223	    rf_wr_cmd_open <= 1'b0;
224	  end else begin
225	    if (rf_wr_cmd_ovld & rf_wr_cmd_ordy)  
226	        rf_wr_cmd_open <= 1'b1;
227	    else if(rf_wr_row_end) 
228	        rf_wr_cmd_open <= 1'b0;
229	  end
230	end
231	
232	////////////////////////////////////////////////////////////////////////////////////////
233	///////////////////////////generate rf write address & data ////////////////////////////
234	assign  data_fifo_rdy = rf_wr_cmd_open & rf_wr_rdy & ~rf_full & data_fifo_vld;  //fifo random stall
235	assign  rf_wr_vld  = data_fifo_vld & data_fifo_rdy;
236	assign  rf_wr_data = data_fifo_pd[511:0]; 
237	assign  rf_wr_done = rf_wr_row_end;
238	
239	//in contract mode,when write one row is done,wr_addr should skip to a fix address
240	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
241	  if (!nvdla_core_rstn) begin
242	    rf_wr_addr <= {5{1'b0}};
243	  end else begin
244	    if (rf_wr_row_end) begin
245	        rf_wr_addr <= 5'h0;
246	    end 
247	    else if(m_contract & rf_wr_col_end) begin  
248	        rf_wr_addr <= {rf_wr_rcnt_inc[2:0],2'b0};
249	    end
250	    else if(~m_split & ~m_contract & ~m_byte_data & rf_wr_col_end) begin  
251	        rf_wr_addr <= {rf_wr_rcnt_inc[3:0],1'b0};
252	    end
253	    else if(rf_wr_vld) begin
254	        rf_wr_addr <= rf_wr_addr + 1'b1;
255	    end
256	  end
257	end
258	
259	//rf column counter & row counter
260	assign  rf_wr_ccnt_inc[5:0] = rf_wr_ccnt + 1;
261	assign  {mon_wr_tcol_c,wr_total_colm[5:0]} = wr_total_col[6:1]+wr_total_col[0];
262	assign  rf_wr_col_end  = rf_wr_vld & (rf_wr_ccnt_inc >= wr_total_colm);
263	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
264	  if (!nvdla_core_rstn) begin
265	    rf_wr_ccnt <= {5{1'b0}};
266	    {mon_rf_wr_ccnt,rf_wr_ccnt} <= {6{1'b0}};
267	  end else begin
268	    if (rf_wr_col_end) begin
269	        rf_wr_ccnt <= 5'h0;
270	    end 
271	    else if(rf_wr_vld) begin
272	        {mon_rf_wr_ccnt,rf_wr_ccnt} <= rf_wr_ccnt_inc;
273	    end
274	  end
275	end
276	
277	assign  rf_wr_rcnt_inc[5:0] = rf_wr_rcnt + 1;
278	assign  rf_wr_row_end  = rf_wr_col_end  & (rf_wr_rcnt_inc == wr_total_row);
279	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
280	  if (!nvdla_core_rstn) begin
281	    rf_wr_rcnt <= {5{1'b0}};
282	    {mon_rf_wr_rcnt,rf_wr_rcnt} <= {6{1'b0}};
283	  end else begin
284	    if (rf_wr_row_end) begin
285	        rf_wr_rcnt <= 5'h0;
286	    end 
287	    else if(rf_wr_col_end) begin
288	        {mon_rf_wr_rcnt,rf_wr_rcnt} <= rf_wr_rcnt_inc;
289	    end
290	  end
291	end
292	
293	NV_NVDLA_RUBIK_rf_wcmd rbk_rf_wr_cmd_fifo (
294	   .nvdla_core_clk  (nvdla_core_clk)      //|< i
295	  ,.nvdla_core_rstn (nvdla_core_rstn)     //|< i
296	  ,.idata_prdy      (rf_wr_cmd_rdy)       //|> o
297	  ,.idata_pvld      (rf_wr_cmd_vld)       //|< i
298	  ,.idata_pd        (rf_wr_cmd_pd[10:0])  //|< i
299	  ,.odata_prdy      (rf_wr_cmd_ordy)      //|< w
300	  ,.odata_pvld      (rf_wr_cmd_ovld)      //|> w
301	  ,.odata_pd        (rf_wr_cmd_opd[10:0]) //|> w
302	  ,.pwrbus_ram_pd   (pwrbus_ram_pd[31:0]) //|< i
303	  );
304	
305	////////////////////////////////////////////////////////////////////////////////
306	//////////////pop total row,total columun from rf_rd_cmd_fifo//////////
307	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
308	  if (!nvdla_core_rstn) begin
309	    rf_rd_cmd_ordy_hold <= 1'b1;
310	  end else begin
311	    if (rf_rd_cmd_ordy_hold & rf_rd_cmd_ovld)  
312	        rf_rd_cmd_ordy_hold <= 1'b0;
313	    else if(rf_rd_grp_end & ~rf_rd_cmd_ovld) 
314	        rf_rd_cmd_ordy_hold <= 1'b1;
315	  end
316	end
317	
318	assign  rf_rd_cmd_ordy = rf_rd_grp_end | rf_rd_cmd_ordy_hold;
319	
320	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
321	  if (!nvdla_core_rstn) begin
322	    rf_rd_cmd_open <= 1'b0;
323	  end else begin
324	    if (rf_rd_cmd_ovld & rf_rd_cmd_ordy)  
325	        rf_rd_cmd_open <= 1'b1;
326	    else if(rf_rd_grp_end) 
327	        rf_rd_cmd_open <= 1'b0;
328	  end
329	end
330	
331	//merge and split of read total column unit is element(1byte or 2byte), but contract unit is 32bytes 
332	assign  rd_total_pcol[6:0] = rf_rd_cmd_opd[5:0]+1; 
333	assign  rd_total_prow[6:0] = rf_rd_cmd_opd[11:6]+1;
334	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
335	  if (!nvdla_core_rstn) begin
336	    rd_total_col_reg[6:0] <= {7{1'b0}};
337	    rd_total_row_reg[6:0] <= {7{1'b0}};
338	  end else begin
339	    if (rf_rd_cmd_ovld & rf_rd_cmd_ordy) begin  
340	        rd_total_col_reg[6:0] <= rd_total_pcol[6:0];
341	        rd_total_row_reg[6:0] <= rd_total_prow[6:0];
342	    end
343	  end
344	end
345	
346	assign  rd_total_col_tmp[6:0] = rd_total_col_reg[6:0]; 
347	assign  rd_total_row_tmp[6:0] = rd_total_row_reg[6:0]; 
348	
349	assign  rd_grp_num[11:0]  = |inwidth[2:0] ? inwidth[13:3]+1 : inwidth[13:3];
350	assign  rd_total_col[6:0] = m_contract ? rd_total_col_tmp : m_split ? (m_byte_data ? 2'h2 : rd_total_col_tmp > 8'h20 ? 4'h4 : 4'h2) : rd_total_row_tmp;  
351	assign  rd_total_row[6:0] = contract_lit_dx ? (rf_rd_gcnt_inc == rd_grp_num ? (|inwidth[2:0] ? inwidth[2:0] : 7'h8) : 7'h8) : (m_contract | m_split) ? rd_total_row_tmp : 1'b1;  
352	
353	////////////////////////////////////////////////////////////////////////////////////////
354	///////////////////////////generate rf read address ///////////////////////////////////
355	assign   rf_rd_vld  = rf_rd_rdy & rf_nempty & rf_rd_cmd_open; 
356	assign   rf_rd_done = rf_rd_row_end;
357	
358	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
359	  if (!nvdla_core_rstn) begin
360	    rf_rd_addr <= {5{1'b0}};
361	  end else begin
362	    if (rf_rd_row_end) begin
363	        rf_rd_addr <= 5'h0;
364	    end 
365	    else if(m_contract & rf_rd_col_end) begin  
366	        rf_rd_addr <= {rf_rd_rcnt_inc[2:0],2'b0};
367	    end
368	    else if(m_split & ~m_byte_data & rf_rd_col_end) begin  
369	        rf_rd_addr <= {rf_rd_rcnt_inc[3:0],1'b0};
370	    end
371	    else if(rf_rd_vld) begin
372	        rf_rd_addr <= rf_rd_addr + 1'b1;
373	    end
374	  end
375	end
376	
377	assign  rf_rd_ccnt_inc[5:0] = rf_rd_ccnt + 1; 
378	assign  {mon_rd_tcol_c,rd_total_colm[5:0]} = rd_total_col[6:1] + rd_total_col[0];
379	assign  rf_rd_col_end   = rf_rd_vld & (rf_rd_ccnt_inc >= rd_total_colm);
380	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
381	  if (!nvdla_core_rstn) begin
382	    rf_rd_ccnt <= {5{1'b0}};
383	    {mon_rf_rd_ccnt,rf_rd_ccnt} <= {6{1'b0}};
384	  end else begin
385	    if (rf_rd_col_end) begin
386	        rf_rd_ccnt <= 5'h0;
387	    end 
388	    else if(rf_rd_vld) begin
389	        {mon_rf_rd_ccnt,rf_rd_ccnt} <= rf_rd_ccnt_inc;
390	    end
391	  end
392	end
393	
394	assign  rf_rd_rcnt_inc[6:0] = rf_rd_rcnt + 1;
395	assign  rf_rd_row_end  = rf_rd_col_end  & (rf_rd_rcnt_inc == rd_total_row);
396	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
397	  if (!nvdla_core_rstn) begin
398	    rf_rd_rcnt <= {6{1'b0}};
399	    {mon_rf_rd_rcnt,rf_rd_rcnt} <= {7{1'b0}};
400	  end else begin
401	    if (rf_rd_row_end) begin
402	        rf_rd_rcnt <= 6'h0;
403	    end 
404	    else if(rf_rd_col_end) begin
405	        {mon_rf_rd_rcnt,rf_rd_rcnt} <= rf_rd_rcnt_inc;
406	    end
407	  end
408	end
409	
410	assign  rf_rd_gcnt_inc[11:0] = rf_rd_gcnt + 1;
411	assign  rf_rd_grp_end  = rf_rd_row_end  & (rf_rd_gcnt_inc == (contract_lit_dx ? rd_grp_num : 1'b1));
412	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
413	  if (!nvdla_core_rstn) begin
414	    rf_rd_gcnt <= {11{1'b0}};
415	    {mon_rf_rd_gcnt,rf_rd_gcnt} <= {12{1'b0}};
416	  end else begin
417	    if (rf_rd_grp_end) begin
418	        rf_rd_gcnt <= 11'h0;
419	    end 
420	    else if(rf_rd_row_end) begin
421	        {mon_rf_rd_gcnt,rf_rd_gcnt} <= rf_rd_gcnt_inc;
422	    end
423	  end
424	end
425	
426	/////////////generate the 64byte data mask//////////
427	//rf_rd_mask[5:0]  : how many valid byte of atomic0
428	//rf_rd_mask[11:6] : how many valid byte of atomic1
429	assign  {mon_remain_rd_row,remain_rd_row[6:0]} = rd_total_row_tmp - {rf_rd_ccnt,1'b0};
430	assign  {mon_remain_rd_col,remain_rd_col[6:0]} = rd_total_col_tmp - {rf_rd_ccnt,1'b0};
431	
432	assign  rd_byte_num[7:0]  = m_byte_data ? {1'b0,rd_total_col_tmp} : {rd_total_col_tmp,1'b0};
433	assign  {mon_remain_byte, remain_byte[7:0] } = rd_byte_num - {rf_rd_ccnt[1:0],6'h0};
434	assign  {mon_remain_byte1,remain_byte1[7:0]} = rd_byte_num - {rf_rd_ccnt[1:0],6'h0} - 8'h20;
435	
436	assign  split_rd_mask[11:0] = (remain_byte >= 8'h40) ? {6'h20,6'h20} : 
437	                              (remain_byte >= 8'h20) ? {remain_byte1[5:0],6'h20} : {6'h0,remain_byte[5:0]}; 
438	
439	assign  merge_byte_mask[5:0] = m_byte_data ? rd_total_col_tmp[5:0] : {rd_total_col_tmp[4:0],1'b0};  
440	assign  merge_atom_mask[1:0] = remain_rd_row == 7'b1 ? 2'b01 : 2'b11; 
441	assign  merge_rd_mask[11:0]  = ~merge_atom_mask[1] ? {6'h0,merge_byte_mask[5:0]} : {merge_byte_mask[5:0],merge_byte_mask[5:0]}; 
442	
443	assign  contract_atom_mask[1:0] = remain_rd_col == 7'b1 ? 2'b01 : 2'b11;
444	assign  contract_rd_mask[11:0]  = ~contract_atom_mask[1] ? {6'h0,6'h20} : {6'h20,6'h20}; 
445	
446	assign  rf_rd_mask[11:0] = m_contract ? contract_rd_mask : m_split ? split_rd_mask : merge_rd_mask;
447	
448	NV_NVDLA_RUBIK_rf_rcmd rbk_rf_rd_cmd_fifo (
449	   .nvdla_core_clk  (nvdla_core_clk)      //|< i
450	  ,.nvdla_core_rstn (nvdla_core_rstn)     //|< i
451	  ,.idata_prdy      (rf_rd_cmd_rdy)       //|> o
452	  ,.idata_pvld      (rf_rd_cmd_vld)       //|< i
453	  ,.idata_pd        (rf_rd_cmd_pd[11:0])  //|< i
454	  ,.odata_prdy      (rf_rd_cmd_ordy)      //|< w
455	  ,.odata_pvld      (rf_rd_cmd_ovld)      //|> w
456	  ,.odata_pd        (rf_rd_cmd_opd[11:0]) //|> w
457	  ,.pwrbus_ram_pd   (pwrbus_ram_pd[31:0]) //|< i
458	  );
459	
460	////////////////rf status////////////////////
461	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
462	  if (!nvdla_core_rstn) begin
463	    rf_wptr[1:0] <= {2{1'b0}};
464	  end else begin
465	    if (rf_wr_done)
466	        rf_wptr[1:0] <= rf_wptr[1:0] + 1;
467	  end
468	end
469	
470	always @(posedge nvdla_core_clk or negedge nvdla_core_rstn) begin
471	  if (!nvdla_core_rstn) begin
472	    rf_rptr[1:0] <= {2{1'b0}};
473	  end else begin
474	    if (rf_rd_done)
475	        rf_rptr[1:0] <= rf_rptr[1:0]+1;
476	  end
477	end
478	
479	assign  rf_nempty = ~(rf_wptr[1:0]==rf_rptr[1:0]);
480	assign  rf_full   = (rf_wptr[1]^rf_rptr[1]) & (rf_wptr[0]==rf_rptr[0]);
481	
482	
483	//VCS coverage off
484	`ifndef DISABLE_FUNCPOINT
485	  `ifdef ENABLE_FUNCPOINT
486	
487	    reg funcpoint_cover_off;
488	    initial begin
489	        if ( $test$plusargs( "cover_off" ) ) begin
490	            funcpoint_cover_off = 1'b1;
491	        end else begin
492	            funcpoint_cover_off = 1'b0;
493	        end
494	    end
495	
496	    property rubik_rf_ctrl__rf_wr_cmd_pop_block__0_cov;
497	        disable iff((nvdla_core_rstn !== 1) || funcpoint_cover_off)
498	        @(posedge nvdla_core_clk)
499	        rf_wr_row_end & ~rf_wr_cmd_ovld;
500	    endproperty
501	    // Cover 0 : "rf_wr_row_end & ~rf_wr_cmd_ovld"
502	    FUNCPOINT_rubik_rf_ctrl__rf_wr_cmd_pop_block__0_COV : cover property (rubik_rf_ctrl__rf_wr_cmd_pop_block__0_cov);
503	
504	  `endif
505	`endif
506	//VCS coverage on
507	
508	//VCS coverage off
509	`ifndef DISABLE_FUNCPOINT
510	  `ifdef ENABLE_FUNCPOINT
511	
512	    property rubik_rf_ctrl__rf_wr_data_full__1_cov;
513	        disable iff((nvdla_core_rstn !== 1) || funcpoint_cover_off)
514	        @(posedge nvdla_core_clk)
515	        ((data_fifo_vld) && nvdla_core_rstn) |-> (rf_wr_rdy & rf_full);
516	    endproperty
517	    // Cover 1 : "rf_wr_rdy & rf_full"
518	    FUNCPOINT_rubik_rf_ctrl__rf_wr_data_full__1_COV : cover property (rubik_rf_ctrl__rf_wr_data_full__1_cov);
519	
520	  `endif
521	`endif
522	//VCS coverage on
523	
524	//VCS coverage off
525	`ifndef DISABLE_FUNCPOINT
526	  `ifdef ENABLE_FUNCPOINT
527	
528	    property rubik_rf_ctrl__rf_rd_cmd_pop_block__2_cov;
529	        disable iff((nvdla_core_rstn !== 1) || funcpoint_cover_off)
530	        @(posedge nvdla_core_clk)
531	        rf_rd_grp_end & ~rf_rd_cmd_ovld;
532	    endproperty
533	    // Cover 2 : "rf_rd_grp_end & ~rf_rd_cmd_ovld"
534	    FUNCPOINT_rubik_rf_ctrl__rf_rd_cmd_pop_block__2_COV : cover property (rubik_rf_ctrl__rf_rd_cmd_pop_block__2_cov);
535	
536	  `endif
537	`endif
538	//VCS coverage on
539	
540	//VCS coverage off
541	`ifndef DISABLE_FUNCPOINT
542	  `ifdef ENABLE_FUNCPOINT
543	
544	    property rubik_rf_ctrl__rf_rd_data_after_cmd__3_cov;
545	        disable iff((nvdla_core_rstn !== 1) || funcpoint_cover_off)
546	        @(posedge nvdla_core_clk)
547	        ~rf_rd_cmd_open & rf_rd_rdy & rf_nempty;
548	    endproperty
549	    // Cover 3 : "~rf_rd_cmd_open & rf_rd_rdy & rf_nempty"
550	    FUNCPOINT_rubik_rf_ctrl__rf_rd_data_after_cmd__3_COV : cover property (rubik_rf_ctrl__rf_rd_data_after_cmd__3_cov);
551	
552	  `endif
553	`endif
554	//VCS coverage on
555	
556	//VCS coverage off
557	`ifndef DISABLE_FUNCPOINT
558	  `ifdef ENABLE_FUNCPOINT
559	
560	    property rubik_rf_ctrl__rf_rd_data_empty__4_cov;
561	        disable iff((nvdla_core_rstn !== 1) || funcpoint_cover_off)
562	        @(posedge nvdla_core_clk)
563	        ((rf_rd_cmd_open) && nvdla_core_rstn) |-> (rf_rd_rdy & ~rf_nempty);
564	    endproperty
565	    // Cover 4 : "rf_rd_rdy & ~rf_nempty"
566	    FUNCPOINT_rubik_rf_ctrl__rf_rd_data_empty__4_COV : cover property (rubik_rf_ctrl__rf_rd_data_empty__4_cov);
567	
568	  `endif
569	`endif
570	//VCS coverage on
571	
572	
573	endmodule // NV_NVDLA_RUBIK_rf_ctrl
574	
