185	function [511:0] shift512_16b; //shift 512bits data with 16bits per one step
186	input [511:0] di;
187	input [4:0] snum;
188	reg [511:0] shf0;
189	reg [511:0] shf1;
190	reg [511:0] shf2;
191	reg [511:0] shf3;
192	begin
193	    shf0[511:0] = snum[4] ? {  di[255:0],  di[511:256]} :   di[511:0];
194	    shf1[511:0] = snum[3] ? {shf0[127:0],shf0[511:128]} : shf0[511:0];
195	    shf2[511:0] = snum[2] ? {shf1[63:0],shf1[511:64]} : shf1[511:0];
196	    shf3[511:0] = snum[1] ? {shf2[31:0],shf2[511:32]} : shf2[511:0];
197	    shift512_16b= snum[0] ? {shf3[15:0],shf3[511:16]} : shf3[511:0];
198	end
